//! Fastify framework recognizer.
//!
//! Detects Fastify apps by import pattern and extracts route and hook
//! registrations from direct app instances.

use std::collections::HashMap;

use crate::cfg::ControlFlowGraph;
use crate::framework_recognizer::{
    FrameworkRecognizer, FrameworkTopology, HttpMethod, Middleware, Route,
};

pub struct FastifyRecognizer;

impl FrameworkRecognizer for FastifyRecognizer {
    fn framework_id(&self) -> &str {
        "fastify"
    }

    fn language(&self) -> &str {
        "typescript"
    }

    fn detect(
        &self,
        source: &str,
        file_path: &str,
        cfgs: &[ControlFlowGraph],
    ) -> Option<FrameworkTopology> {
        let has_fastify = source.contains("from 'fastify'")
            || source.contains("from \"fastify\"")
            || source.contains("require('fastify')")
            || source.contains("require(\"fastify\")");

        if !has_fastify {
            return None;
        }

        let mut routes = Vec::new();
        let mut middleware = Vec::new();
        let mut middleware_order = 0;
        let app_names = detect_app_names(source);
        let lines: Vec<&str> = source.lines().collect();

        for (index, line) in lines.iter().enumerate() {
            let trimmed = line.trim();

            for app_name in &app_names {
                for (method_name, method) in &[
                    ("get", HttpMethod::Get),
                    ("post", HttpMethod::Post),
                    ("put", HttpMethod::Put),
                    ("delete", HttpMethod::Delete),
                    ("patch", HttpMethod::Patch),
                    ("head", HttpMethod::Head),
                    ("options", HttpMethod::Options),
                    ("all", HttpMethod::All),
                ] {
                    let pattern = format!("{}.{}(", app_name, method_name);
                    if let Some(start) = trimmed.find(&pattern) {
                        let after_paren = start + pattern.len();
                        if let Some(path) = extract_string_arg(&trimmed[after_paren..]) {
                            let handler_name = extract_js_handler_name(&trimmed[after_paren..])
                                .unwrap_or_else(|| {
                                    format!("{}_{}", method_name, sanitize_path(&path))
                                });

                            let handler_cfg_index = cfgs
                                .iter()
                                .position(|cfg| cfg.function_name == handler_name);

                            routes.push(Route {
                                method: method.clone(),
                                path,
                                handler_name,
                                handler_cfg_index,
                                source_start: 0,
                                source_end: 0,
                            });
                        }
                    }
                }

                let hook_pattern = format!("{}.addHook(", app_name);
                if trimmed.starts_with(&hook_pattern) {
                    let rest = &trimmed[hook_pattern.len()..];
                    let hook_name = extract_string_arg(rest);
                    if matches!(hook_name.as_deref(), Some("onRequest" | "preHandler")) {
                        let middleware_name = extract_js_handler_name(rest)
                            .or_else(|| find_callback_name(&lines, index + 1))
                            .unwrap_or_else(|| "fastify_hook".to_string());
                        middleware.push(Middleware {
                            name: middleware_name,
                            path_prefix: None,
                            handler_cfg_index: None,
                            order: middleware_order,
                        });
                        middleware_order += 1;
                    }
                }
            }
        }

        if routes.is_empty() {
            return None;
        }

        Some(FrameworkTopology {
            framework: "fastify".to_string(),
            language: "typescript".to_string(),
            file_path: file_path.to_string(),
            routes,
            middleware,
            listen_port: detect_fastify_port(source, &app_names),
            config: HashMap::new(),
        })
    }
}

fn detect_app_names(source: &str) -> Vec<String> {
    let mut names = Vec::new();

    for line in source.lines() {
        let trimmed = line.trim();
        for prefix in &["const ", "let ", "var "] {
            if trimmed.starts_with(prefix)
                && (trimmed.contains("= fastify(") || trimmed.contains("= Fastify("))
            {
                if let Some(name) = trimmed
                    .strip_prefix(prefix)
                    .and_then(|rest| rest.split('=').next())
                    .map(|candidate| candidate.trim().to_string())
                {
                    if !name.is_empty() {
                        names.push(name);
                    }
                }
            }
        }
    }

    if names.is_empty() {
        names.push("app".to_string());
    }

    names
}

fn extract_string_arg(s: &str) -> Option<String> {
    let s = s.trim();
    let quote = s.chars().next()?;
    if quote != '\'' && quote != '"' && quote != '`' {
        return None;
    }
    let rest = &s[1..];
    let end = rest.find(quote)?;
    Some(rest[..end].to_string())
}

fn extract_js_handler_name(s: &str) -> Option<String> {
    let after_path = s.find(',')? + 1;
    let rest = s[after_path..].trim();
    if rest.starts_with('{') {
        if let Some(handler_index) = rest.find("handler:") {
            let handler_rest = rest[handler_index + "handler:".len()..].trim();
            let name: String = handler_rest
                .chars()
                .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
                .collect();
            if !name.is_empty() {
                return Some(name);
            }
        }
    }

    if rest.starts_with('(') || rest.starts_with("async") || rest.starts_with("function") {
        return None;
    }

    let name: String = rest
        .chars()
        .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
        .collect();

    if name.is_empty() {
        None
    } else {
        Some(name)
    }
}

fn find_callback_name(lines: &[&str], start: usize) -> Option<String> {
    for line in lines.iter().skip(start) {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        if let Some(rest) = trimmed.strip_prefix("function ") {
            let name: String = rest
                .chars()
                .take_while(|c| c.is_alphanumeric() || *c == '_')
                .collect();
            if !name.is_empty() {
                return Some(name);
            }
        }
        break;
    }
    None
}

fn detect_fastify_port(source: &str, app_names: &[String]) -> Option<u16> {
    for line in source.lines() {
        let trimmed = line.trim();
        for app_name in app_names {
            let pattern = format!("{}.listen(", app_name);
            if let Some(start) = trimmed.find(&pattern) {
                let after_paren = start + pattern.len();
                let rest = &trimmed[after_paren..];
                if let Some(port_index) = rest.find("port:") {
                    let num_str: String = rest[port_index + "port:".len()..]
                        .chars()
                        .skip_while(|c| c.is_whitespace())
                        .take_while(|c| c.is_ascii_digit())
                        .collect();
                    if let Ok(port) = num_str.parse::<u16>() {
                        return Some(port);
                    }
                }

                let num_str: String = rest.chars().take_while(|c| c.is_ascii_digit()).collect();
                if let Ok(port) = num_str.parse::<u16>() {
                    return Some(port);
                }
            }
        }
    }
    None
}

fn sanitize_path(path: &str) -> String {
    path.chars()
        .map(|c| if c.is_alphanumeric() { c } else { '_' })
        .collect::<String>()
        .trim_matches('_')
        .to_string()
}
